Actionscript.script:
if (NGIO.audio.muted === false) {
	// TODO: AS2 Sound API differs. Equivalent:
	//       var snd:Sound = new Sound(this.sound_in);
	//       snd.setVolume(NGIO.audio.volume * 100);
	//       snd.start();
	// this.sound_in.play(0, 0, new SoundTransform(NGIO.audio.volume));
}

if (this.medalQueue.length > 0) {
	gotoAndStop('hidden');
} else if (NGIO.audio.muted === false) {
	// TODO: AS2 Sound API differs. Equivalent:
	//       var snd:Sound = new Sound(this.sound_out);
	//       snd.setVolume(NGIO.audio.volume * 100);
	//       snd.start();
	// this.sound_out.play(0, 0, new SoundTransform(NGIO.audio.volume));
}

var sound_in = new __ngio_medalsound_in();
var sound_out = new __ngio_medalsound_out();

this.medalQueue = [];
this.hiddenFrame = 0;

if (NGIO.core == null) {
	throw new Error("Medal popup will not work without the connector component");
}

NGIO.medalPopup = this;

function unlockNext():Void {
	if (this.currentFrame <= this.hiddenFrame && this.medalQueue.length > 0) {
		this.medal = this.medalQueue.shift();
		this.gotoAndPlay('unlock');
	}
}

function unlock(medal_id):Void {
	if (!NGIO.hasUser()) return;

	var medal = NGIO.getMedal(medal_id);

	if (!medal) {
		throw new Error("Couldn't find medal with ID " + medal_id);
	}

	if (medal.unlocked) {
		if (this.show_even_if_unlocked) {
			if (NGIO.core.useDebugMode) {
				trace("NGIO Notice: The medal, '" + medal.name + "' was already unlocked");
			}
			this.medalQueue.push(medal);
			this.unlockNext();
		}
		return;
	}

	medal.unlock(
		function(unlockedMedal, medalScore) {
			this.medalQueue.push(unlockedMedal);
			this.unlockNext();
		},
		this
	);
}

gotoAndStop('hidden');
